  display:flex;align-items:center;padding:0 10px 0 12px;
  color:#999;cursor:pointer;font-size:13px;white-space:nowrap;
  border-right:1px solid #222;gap:6px;min-width:80px;
  transition:background 0.1s,color 0.1s;
}
