  <div class="window" id="notepad-window">
    <div class="win-titlebar" id="notepad-drag-handle">
      <div class="win-controls">
        <button class="win-btn win-close" data-win="notepad-window"></button>
        <button class="win-btn win-min"></button>
        <button class="win-btn win-max"></button>
