</div>
<script>
// ═══════════════════════════════════════════
//  FILESYSTEM
// ═══════════════════════════════════════════
const FS = {
  '/':                          {type:'dir', children:['bin','etc','home','usr','var']},
  '/bin':                       {type:'dir', children:['bash','ls','cat','cp','mv','rm','mkdir','grep','chmod','echo']},
  '/etc':                       {type:'dir', children:['hosts','fstab','passwd','shadow','group','hostname','resolv.conf','apt']},
  '/etc/apt':                   {type:'dir', children:['sources.list','preferences']},
  '/home':                      {type:'dir', children:['user']},
  '/home/user':                 {type:'dir', children:['Documents','Downloads','Pictures','.bashrc','.profile','.ssh']},
  '/home/user/.ssh':            {type:'dir', children:['id_rsa','id_rsa.pub','known_hosts']},
  '/home/user/Documents':       {type:'dir', children:['resume.txt','notes.txt','todo.txt','Projects','Work']},
  '/home/user/Documents/Projects':{type:'dir', children:['webapp','scripts','data-analysis']},
  '/home/user/Documents/Projects/webapp':{type:'dir', children:['index.html','style.css','app.js','README.md']},
  '/home/user/Documents/Projects/scripts':{type:'dir', children:['backup.sh','deploy.sh','cleanup.sh']},
  '/home/user/Documents/Projects/data-analysis':{type:'dir', children:['analysis.py','data.csv','report.pdf']},
  '/home/user/Documents/Work':  {type:'dir', children:['meeting-notes.txt','Q3-report.pdf','budget.xlsx']},
  '/home/user/Downloads':       {type:'dir', children:['ubuntu-24.04.iso','setup.sh','archive.tar.gz','photo-backup.zip']},
  '/home/user/Pictures':        {type:'dir', children:['wallpaper.png','screenshot.png','avatar.jpg','Vacation','Screenshots']},
  '/home/user/Pictures/Vacation':{type:'dir', children:['beach.jpg','sunset.jpg','city.jpg','hiking.jpg']},
  '/home/user/Pictures/Screenshots':{type:'dir', children:['desktop-2024.png','error-log.png']},
  '/usr':                       {type:'dir', children:['bin','lib','share','local','include']},
  '/usr/bin':                   {type:'dir', children:['python3','node','git','vim','nano','curl','wget','ssh','gcc']},
  '/usr/lib':                   {type:'dir', children:['systemd','udev','python3','x86_64-linux-gnu']},
  '/usr/share':                 {type:'dir', children:['applications','doc','fonts','icons','man','locale']},
  '/usr/local':                 {type:'dir', children:['bin','lib','share','etc']},
  '/usr/include':               {type:'dir', children:['stdio.h','stdlib.h','string.h']},
  '/var':                       {type:'dir', children:['log','tmp','cache','lib','run','spool']},
  '/var/log':                   {type:'dir', children:['syslog','auth.log','kern.log','dpkg.log','apt']},
  '/var/log/apt':               {type:'dir', children:['history.log','term.log']},
  '/var/tmp':                   {type:'dir', children:[]},
  '/var/cache':                 {type:'dir', children:['apt','man','fontconfig']},
  '/var/lib':                   {type:'dir', children:['dpkg','apt','systemd']},
  '/var/run':                   {type:'dir', children:['utmp','sshd.pid']},
  '/var/spool':                 {type:'dir', children:['cron','mail']},
};

function isDir(path){ return FS[path] && FS[path].type === 'dir'; }
function getChildren(path){ return (FS[path] && FS[path].children) || []; }
function joinPath(parent, name){ return parent === '/' ? '/' + name : parent + '/' + name; }

const FILE_ICONS = {
  dir:'📁', sh:'⚙️', bash:'⚙️', txt:'📄', md:'📝',
  js:'📜', html:'🌐', css:'🎨', py:'🐍',
  png:'🖼️', jpg:'🖼️', jpeg:'🖼️', gif:'🖼️', svg:'🖼️',
  iso:'💿', tar:'📦', gz:'📦', zip:'📦',
  log:'📋', conf:'⚙️', cfg:'⚙️', list:'📋',
  pdf:'📕', xlsx:'📊', csv:'📊',
  pub:'🔑', rsa:'🔑', h:'📎', c:'📎',
};
function iconFor(fullPath, name){
  if(isDir(fullPath)) return '📁';
  const ext = name.includes('.') ? name.split('.').pop().toLowerCase() : name.toLowerCase();
  return FILE_ICONS[ext] || FILE_ICONS[name] || '📄';
}

// ═══════════════════════════════════════════
//  FILES APP
// ═══════════════════════════════════════════
let currentPath = '/';

function renderFiles(){
  const pathEl = document.getElementById('files-path');
  const list   = document.getElementById('files-list');
  pathEl.textContent = currentPath;
  list.innerHTML = '';

  const children = getChildren(currentPath);
  if(children.length === 0){
    list.innerHTML = '<div style="color:#666;padding:20px;font-size:13px;">Empty directory</div>';
    return;
  }
  children.forEach(name => {
    const full = joinPath(currentPath, name);
    const item = document.createElement('div');
    item.className = 'fs-item';
    item.innerHTML = `<span class="fs-icon">${iconFor(full,name)}</span><span class="fs-name">${name}</span>`;
    item.addEventListener('click', e => {
      document.querySelectorAll('.fs-item').forEach(i=>i.classList.remove('selected'));
      item.classList.add('selected');
      e.stopPropagation();
    });
    item.addEventListener('dblclick', () => {
      if(isDir(full)){ currentPath = full; renderFiles(); }
    });
    list.appendChild(item);
  });
}

document.getElementById('files-list').addEventListener('click', () => {
  document.querySelectorAll('.fs-item').forEach(i=>i.classList.remove('selected'));
});

document.getElementById('files-up').addEventListener('click', () => {
  if(currentPath === '/') return;
  const parts = currentPath.split('/').filter(Boolean);
  parts.pop();
  currentPath = parts.length === 0 ? '/' : '/' + parts.join('/');
  renderFiles();
});

// ═══════════════════════════════════════════
//  NOTEPAD (tabbed, localStorage)
// ═══════════════════════════════════════════
const LS_KEY = 'desktop_notepad_v1';
let notepadTabs = [];
let activeTab   = null;
let tabCounter  = 0;

function loadNotepadState(){
  try{
    const raw = localStorage.getItem(LS_KEY);
    if(raw){
      const state = JSON.parse(raw);
      notepadTabs = state.tabs || [];
      tabCounter  = state.counter || notepadTabs.length;
      activeTab   = state.activeId || (notepadTabs[0] && notepadTabs[0].id) || null;
    }
  } catch(e){}
  if(notepadTabs.length === 0){
    tabCounter = 0;
    const t = newTabObj();
    notepadTabs.push(t);
    activeTab = t.id;
  }
}

function saveNotepadState(){
  try{
    localStorage.setItem(LS_KEY, JSON.stringify({tabs:notepadTabs, counter:tabCounter, activeId:activeTab}));
  } catch(e){}
}

function newTabObj(){
  tabCounter++;
  return {id:'tab_'+tabCounter, name:'Untitled '+tabCounter, content:''};
}

function flushEditorToActive(){
  const t = notepadTabs.find(t=>t.id===activeTab);
  if(t) t.content = document.getElementById('editor').value;
}

function renderNotepadTabs(){
  const strip = document.getElementById('tabs');
  const btn   = document.getElementById('new-tab');
  strip.querySelectorAll('.tab').forEach(el=>el.remove());
  notepadTabs.forEach(t => {
    const el = document.createElement('div');
    el.className = 'tab' + (t.id === activeTab ? ' active' : '');
    el.dataset.id = t.id;
    el.innerHTML = `<span class="tab-label">${escHtml(t.name)}</span><span class="tab-x" data-id="${t.id}">&#x2715;</span>`;
    el.addEventListener('click', e => {
      if(e.target.classList.contains('tab-x')) return;
      flushEditorToActive();
      activeTab = t.id;
      document.getElementById('editor').value = t.content;
      renderNotepadTabs();
      saveNotepadState();
    });
    el.querySelector('.tab-x').addEventListener('click', e => {
      e.stopPropagation();
      closeNotepadTab(t.id);
    });
    strip.insertBefore(el, btn);
  });
}

function closeNotepadTab(id){
  flushEditorToActive();
  const idx = notepadTabs.findIndex(t=>t.id===id);
  if(idx === -1) return;
  notepadTabs.splice(idx,1);
  if(notepadTabs.length === 0){
    const t = newTabObj();
    notepadTabs.push(t);
    activeTab = t.id;
  } else if(activeTab === id){
    activeTab = notepadTabs[Math.min(idx, notepadTabs.length-1)].id;
  }
  document.getElementById('editor').value = notepadTabs.find(t=>t.id===activeTab)?.content || '';
  renderNotepadTabs();
  saveNotepadState();
}

document.getElementById('new-tab').addEventListener('click', () => {
  flushEditorToActive();
  const t = newTabObj();
  notepadTabs.push(t);
  activeTab = t.id;
  document.getElementById('editor').value = '';
  renderNotepadTabs();
  saveNotepadState();
  document.getElementById('editor').focus();
});

document.getElementById('editor').addEventListener('input', () => {
  const t = notepadTabs.find(t=>t.id===activeTab);
  if(t){ t.content = document.getElementById('editor').value; saveNotepadState(); }
});

function escHtml(s){ return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

// ═══════════════════════════════════════════
//  WINDOW MANAGEMENT
// ═══════════════════════════════════════════
let zTop = 100;

function openWindow(id){
  const w = document.getElementById(id);
  w.style.display = 'flex';
  bringToFront(w);
}
function closeWindow(id){
  document.getElementById(id).style.display = 'none';
}
function bringToFront(w){
  zTop++;
  w.style.zIndex = zTop;
}

// Close buttons (.win-close)
document.querySelectorAll('.win-close').forEach(btn => {
  btn.addEventListener('click', () => closeWindow(btn.dataset.win));
});

// Launchers
document.getElementById('open-files').addEventListener('click', () => {
  openWindow('files-window');
  renderFiles();
});
document.getElementById('open-notepad').addEventListener('click', () => {
  openWindow('notepad-window');
});

// Focus on click
document.querySelectorAll('.window').forEach(w => {
  w.addEventListener('mousedown', () => bringToFront(w));
});

// ── Drag ──
function makeDraggable(handleId, winId){
  const handle = document.getElementById(handleId);
  const win    = document.getElementById(winId);
  let dragging=false, ox=0, oy=0, wl=0, wt=0;

  handle.addEventListener('mousedown', e => {
    if(e.target.classList.contains('win-btn')) return;
    dragging = true;
    ox = e.clientX; oy = e.clientY;
    wl = win.offsetLeft; wt = win.offsetTop;
    bringToFront(win);
    e.preventDefault();
  });
  document.addEventListener('mousemove', e => {
    if(!dragging) return;
    let nl = wl + (e.clientX - ox);
    let nt = wt + (e.clientY - oy);
    // Clamp so titlebar stays on screen
    nl = Math.max(-win.offsetWidth+80, Math.min(window.innerWidth-80, nl));
    nt = Math.max(28, Math.min(window.innerHeight-40, nt));
    win.style.left = nl+'px';
    win.style.top  = nt+'px';
  });
  document.addEventListener('mouseup', () => { dragging=false; });
}
makeDraggable('files-drag-handle',   'files-window');
makeDraggable('notepad-drag-handle', 'notepad-window');

// ── Touch drag support ──
function makeTouchDraggable(handleId, winId){
  const handle = document.getElementById(handleId);
  const win    = document.getElementById(winId);
  let ox=0, oy=0, wl=0, wt=0;

  handle.addEventListener('touchstart', e => {
    if(e.target.classList.contains('win-btn')) return;
    const t = e.touches[0];
    ox = t.clientX; oy = t.clientY;
    wl = win.offsetLeft; wt = win.offsetTop;
    bringToFront(win);
  }, {passive:true});
  handle.addEventListener('touchmove', e => {
    const t = e.touches[0];
    win.style.left = (wl + t.clientX - ox)+'px';
    win.style.top  = (wt + t.clientY - oy)+'px';
    e.preventDefault();
  }, {passive:false});
}
makeTouchDraggable('files-drag-handle',   'files-window');
makeTouchDraggable('notepad-drag-handle', 'notepad-window');

// ═══════════════════════════════════════════
//  CLOCK
// ═══════════════════════════════════════════
function updateClock(){
  const d = new Date();
  const h = d.getHours().toString().padStart(2,'0');
  const m = d.getMinutes().toString().padStart(2,'0');
  const days = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  document.getElementById('topbar-time').textContent =
    `${days[d.getDay()]} ${d.getDate()} ${months[d.getMonth()]}  ${h}:${m}`;
}
updateClock();
setInterval(updateClock, 10000);

// ═══════════════════════════════════════════
//  INIT
// ═══════════════════════════════════════════
loadNotepadState();
renderNotepadTabs();
document.getElementById('editor').value = notepadTabs.find(t=>t.id===activeTab)?.content || '';
renderFiles();
</script>
</body>
</html>
